import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function buildAgentReputation(agentAddress) {
  const [txns, activity] = await Promise.all([
    client.TransactionService.getTransactionsForAddressV3("eth-mainnet", agentAddress),
    client.AllChainsService.getAddressActivity(agentAddress),
  ]);
  const successRate = (txns.data?.items ?? []).filter(t => t.successful).length /
    Math.max(1, txns.data?.items?.length ?? 1);
  return { agentAddress, successRate, chainsActive: activity.data?.items?.length };
}
